'use client';

import React, { useState } from 'react';
import styled from 'styled-components';
import { useRouter } from 'next/navigation';

const LoginPage: React.FC = () => {
  const router = useRouter();
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [rememberMe, setRememberMe] = useState(false);

  const handleSubmit = (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();

    const correctUser = process.env.NEXT_PUBLIC_POS_USER || 'admin';
    const correctPass = process.env.NEXT_PUBLIC_POS_PASSWORD || '1234';

    if (email === correctUser && password === correctPass) {
      localStorage.setItem('auth_token', 'glossy-secret');
      router.push('/home');
    } else {
      alert('ชื่อผู้ใช้หรือรหัสผ่านไม่ถูกต้อง');
    }
  };

  return (
    <StyledWrapper>
      <form className="form" onSubmit={handleSubmit}>
        <div className="flex-column">
          <label>Email </label>
        </div>
        <div className="inputForm">
          <svg height={20} viewBox="0 0 32 32" width={20} xmlns="http://www.w3.org/2000/svg">
            <path d="..." />
          </svg>
          <input
            type="text"
            className="input"
            placeholder="Enter your Email"
            value={email}
            onChange={(e) => setEmail(e.target.value)}
          />
        </div>
        <div className="flex-column">
          <label>Password </label>
        </div>
        <div className="inputForm">
          <svg height={20} viewBox="..." width={20} xmlns="http://www.w3.org/2000/svg">
            <path d="..." />
          </svg>
          <input
            type="password"
            className="input"
            placeholder="Enter your Password"
            value={password}
            onChange={(e) => setPassword(e.target.value)}
          />
        </div>
        <div className="flex-row">
          <div>
            <input
              type="checkbox"
              checked={rememberMe}
              onChange={(e) => setRememberMe(e.target.checked)}
            />
            <label>Remember me </label>
          </div>
          <span className="span">Forgot password?</span>
        </div>
        <button type="submit" className="button-submit">Sign In</button>
        <p className="p">Don't have an account? <span className="span">Sign Up</span></p>
        <p className="p line">Or With</p>
        <div className="flex-row">
          <button type="button" className="btn google">
            <svg width={20} height={20}><path d="..." /></svg>
            Google
          </button>
          <button type="button" className="btn apple">
            <svg width={20} height={20}><path d="..." /></svg>
            Apple
          </button>
        </div>
      </form>
    </StyledWrapper>
  );
};

const StyledWrapper = styled.div`
  display: flex;
  justify-content: center;
  align-items: center;
  height: 100vh;
  background-color: #f5f5f5;
  ... // KEEP YOUR EXISTING CSS FROM ABOVE
`;

export default LoginPage;
